2	  description = "QBZ — Native hi-fi Qobuz desktop player for Linux";
3	
4	  inputs = {
5	    nixpkgs.url = "github:NixOS/nixpkgs/nixpkgs-unstable";
6	    flake-utils.url = "github:numtide/flake-utils";
