47	            hash  = srcHash;
48	          };
49	
50	          cargoRoot = "crates";
51	          buildAndTestSubdir = cargoRoot;
52	          # Build only the app binary, not every workspace member's tests.
53	          cargoBuildFlags = [ "-p" "qbz" ];
54	
55	          cargoLock = {
56	            lockFile = "${src}/crates/Cargo.lock";
57	          };
58	
59	          env.LIBCLANG_PATH = "${pkgs.lib.getLib pkgs.llvmPackages.libclang}/lib";
60	
61	          nativeBuildInputs = with pkgs; [
62	            clang
63	            pkg-config
64	            cmake
65	            nasm
